// CardinalityLimiter tracks and limits the number of unique label value combinations
type CardinalityLimiter struct {
	mu              sync.RWMutex
	trackedValues   map[string]map[string]time.Time // metric_name -> label_combo_key -> last_seen
	maxCardinality  int
	rejectedTotal   prometheus.Counter
	activeLabelsGauge *prometheus.GaugeVec
}

func NewCardinalityLimiter(maxCardinality int) *CardinalityLimiter {
	cl := &CardinalityLimiter{
		trackedValues:  make(map[string]map[string]time.Time),
		maxCardinality: maxCardinality,
		rejectedTotal: prometheus.NewCounter(prometheus.CounterOpts{
			Name: "metrics_label_rejections_total",
			Help: "Total number of metric updates rejected due to cardinality limits",
		}),
		activeLabelsGauge: prometheus.NewGaugeVec(prometheus.GaugeOpts{
			Name: "metrics_active_label_combinations",
			Help: "Number of active unique label combinations per metric",
		}, []string{"metric_name"}),
	}
	prometheus.MustRegister(cl.rejectedTotal)
	prometheus.MustRegister(cl.activeLabelsGauge)
	return cl
}

func (cl *CardinalityLimiter) Allow(metricName string, labelValues map[string]string) bool {
	key := buildLabelKey(labelValues)

	cl.mu.RLock()
	if vals, ok := cl.trackedValues[metricName]; ok {
		if _, exists := vals[key]; exists {
			cl.mu.RUnlock()
			cl.mu.Lock()
			cl.trackedValues[metricName][key] = time.Now()
			cl.mu.Unlock()
			return true
		}
	}
	cl.mu.RUnlock()

	cl.mu.Lock()
	defer cl.mu.Unlock()

	if cl.trackedValues[metricName] == nil {
		cl.trackedValues[metricName] = make(map[string]time.Time)
	}

	// Double-check after acquiring write lock
	if _, exists := cl.trackedValues[metricName][key]; exists {
		cl.trackedValues[metricName][key] = time.Now()
		return true
	}

	if len(cl.trackedValues[metricName]) >= cl.maxCardinality {
		cl.rejectedTotal.Inc()
		return false
	}

	cl.trackedValues[metricName][key] = time.Now()
	cl.activeLabelsGauge.WithLabelValues(metricName).Set(float64(len(cl.trackedValues[metricName])))
	return true
}

// Cleanup removes label combinations not seen recently
func (cl *CardinalityLimiter) Cleanup(maxAge time.Duration) {
	cl.mu.Lock()
	defer cl.mu.Unlock()

	cutoff := time.Now().Add(-maxAge)
	for metricName, vals := range cl.trackedValues {
		for key, lastSeen := range vals {
			if lastSeen.Before(cutoff) {
				delete(vals, key)
			}
		}
		cl.activeLabelsGauge.WithLabelValues(metricName).Set(float64(len(vals)))
		if len(vals) == 0 {
			delete(cl.trackedValues, metricName)
		}
	}
}

func buildLabelKey(labels map[string]string) string {
	// Build a deterministic key from label values
	parts := make([]string, 0, len(labels))
	for k, v := range labels {
		parts = append(parts, k+"="+v)
	}
	// Sort for determinism
	for i := 0; i < len(parts); i++ {
		for j := i + 1; j < len(parts); j++ {
			if parts[i] > parts[j] {
				parts[i], parts[j] = parts[j], parts[i]
			}
		}
	}
	return strings.Join(parts, ",")
}

// LabelSanitizer validates and normalizes user-provided label values
type LabelSanitizer struct {
	allowedPattern *regexp.Regexp
	allowedValues  map[string]map[string]bool // label_name -> set of allowed values (nil means any sanitized value)
}

func NewLabelSanitizer() *LabelSanitizer {
	return &LabelSanitizer{
		allowedPattern: regexp.MustCompile(`^[a-zA-Z0-9_\-./@ ]+$`),
		allowedValues:  make(map[string]map[string]bool),
	}
}

// RegisterAllowedValues sets an explicit allowlist for a label
func (ls *LabelSanitizer) RegisterAllowedValues(labelName string, values []string) {
	allowed := make(map[string]bool, len(values))
	for _, v := range values {
		allowed[v] = true
	}
	ls.allowedValues[labelName] = allowed
}

func (ls *LabelSanitizer) Sanitize(labelName, value string) (string, bool) {
	if value == "" {
		return "unknown", true
	}

	// Truncate to max length
	if len(value) > labelValueMaxLength {
		value = value[:labelValueMaxLength]
	}

	// Trim whitespace
	value = strings.TrimSpace(value)

	// Check against allowlist if one exists
	if allowed, hasAllowlist := ls.allowedValues[labelName]; hasAllowlist {
		if !allowed[value] {
			return "other", false
		}
		return value, true
	}

	// General pattern validation
	if !ls.allowedPattern.MatchString(value) {
		return "invalid", false
	}

	return value, true
}

// SafeMetrics wraps Prometheus metrics with cardinality protection
type SafeMetrics struct {
	limiter   *CardinalityLimiter
	sanitizer *LabelSanitizer

	requestDuration *prometheus.HistogramVec
	requestTotal    *prometheus.CounterVec
	activeRequests  *prometheus.GaugeVec
	errorsTotal     *prometheus.CounterVec

	// Bucketed user metric - maps user IDs to buckets to limit cardinality
	userRequestTotal *prometheus.CounterVec
}

func NewSafeMetrics(limiter *CardinalityLimiter, sanitizer *LabelSanitizer) *SafeMetrics {
	sm := &SafeMetrics{
		limiter:   limiter,
		sanitizer: sanitizer,

		requestDuration: prometheus.NewHistogramVec(prometheus.HistogramOpts{
			Name:    "http_request_duration_seconds",
			Help:    "HTTP request duration in seconds",
			Buckets: prometheus.DefBuckets,
		}, []string{"method", "endpoint", "status_code"}),

		requestTotal: prometheus.NewCounterVec(prometheus.CounterOpts{
			Name: "http_requests_total",
			Help: "Total number of HTTP requests",
		}, []string{"method", "endpoint", "status_code"}),

		activeRequests: prometheus.NewGaugeVec(prometheus.GaugeOpts{
			Name: "http_active_requests",
			Help: "Number of active HTTP requests",
		}, []string{"method", "endpoint"}),

		errorsTotal: prometheus.NewCounterVec(prometheus.CounterOpts{
			Name: "http_errors_total",
			Help: "Total number of HTTP errors",
		}, []string{"method", "endpoint", "error_type"}),

		// User tracking with bucketed user IDs to prevent explosion
		userRequestTotal: prometheus.NewCounterVec(prometheus.CounterOpts{
			Name: "user_requests_total",
			Help: "Total requests per user bucket and endpoint",
		}, []string{"user_bucket", "endpoint", "method"}),
	}

	prometheus.MustRegister(sm.requestDuration)
	prometheus.MustRegister(sm.requestTotal)
	prometheus.MustRegister(sm.activeRequests)
	prometheus.MustRegister(sm.errorsTotal)
	prometheus.MustRegister(sm.userRequestTotal)

	return sm
}

// BucketUserID maps a user ID to a bucket to limit cardinality
// Instead of tracking each individual user, we group them
func BucketUserID(userID string) string {
	if userID == "" {
		return "anonymous"
	}

	// Use first 2 characters as bucket prefix for bounded cardinality
	// This gives at most 36^2 = 1296 buckets for alphanumeric IDs
	sanitized := strings.ToLower(userID)
	if len(sanitized) < 2 {
		return "bucket_" + sanitized
	}
	return "bucket_" + sanitized[:2]
}

// NormalizeEndpoint maps request paths to a bounded set of endpoint labels
func NormalizeEndpoint(path string) string {
	// Strip query parameters
	if idx := strings.Index(path, "?"); idx != -1 {
		path = path[:idx]
	}

	// Map known patterns to normalized forms
	patterns := []struct {
		prefix     string
		normalized string
	}{
		{"/api/v1/users/", "/api/v1/users/:id"},
		{"/api/v1/orders/", "/api/v1/orders/:id"},
		{"/api/v1/products/", "/api/v1/products/:id"},
		{"/api/v1/users", "/api/v1/users"},
		{"/api/v1/orders", "/api/v1/orders"},
		{"/api/v1/products", "/api/v1/products"},
		{"/health", "/health"},
		{"/metrics", "/metrics"},
	}

	for _, p := range patterns {
		if strings.HasPrefix(path, p.prefix) {
			return p.normalized
		}
	}

	// Unknown endpoints get grouped
	return "/other"
}

func NormalizeMethod(method string) string {
	method = strings.ToUpper(method)
	switch method {
	case "GET", "POST", "PUT", "DELETE", "PATCH", "HEAD", "OPTIONS":
		return method
	default:
		return "OTHER"
	}
}

func NormalizeStatusCode(code int) string {
	// Group status codes into classes to limit cardinality
	switch {
	case code >= 200 && code < 300:
		return "2xx"
	case code >= 300 && code < 400:
		return "3xx"
	case code >= 400 && code < 500:
		return "4xx"
	case code >= 500 && code < 600:
		return "5xx"
	default:
		return "other"
	}
}

func (sm *SafeMetrics) RecordRequest(method, path, userID string, statusCode int, duration time.Duration) {
	normalizedMethod := NormalizeMethod(method)
	normalizedEndpoint := NormalizeEndpoint(path)
	normalizedStatus := NormalizeStatusCode(statusCode)

	labels := map[string]string{
		"method":      normalizedMethod,
		"endpoint":    normalizedEndpoint,
		"status_code": normalizedStatus,
	}

	if sm.limiter.Allow("http_requests_total", labels) {
		sm.requestTotal.WithLabelValues(normalizedMethod, normalizedEndpoint, normalizedStatus).Inc()
		sm.requestDuration.WithLabelValues(normalizedMethod, normalizedEndpoint, normalizedStatus).Observe(duration.Seconds())
	}

	// Track per-user metrics with bucketing
	userBucket := BucketUserID(userID)
	userLabels := map[string]string{
		"user_bucket": userBucket,
		"endpoint":    normalizedEndpoint,
		"method":      normalizedMethod,
	}

	if sm.limiter.Allow("user_requests_total", userLabels) {
		sm.userRequestTotal.WithLabelValues(userBucket, normalizedEndpoint, normalizedMethod).Inc()
	}
}

func (sm *SafeMetrics) RecordError(method, path, errorType string) {
	normalizedMethod := NormalizeMethod(method)
	normalizedEndpoint := NormalizeEndpoint(path)

	// Sanitize user-provided error type
	sanitizedErrorType, _ := sm.sanitizer.Sanitize("error_type", errorType)

	labels := map[string]string{
		"method":     normalizedMethod,
		"endpoint":   normalizedEndpoint,
		"error_type": sanitizedErrorType,
	}

	if sm.limiter.Allow("http_errors_total", labels) {
		sm.errorsTotal.WithLabelValues(normalizedMethod, normalizedEndpoint, sanitizedErrorType).Inc()
	}
}

func (sm *SafeMetrics) TrackActiveRequest(method, path string) func() {
	normalizedMethod := NormalizeMethod(method)
	normalizedEndpoint := NormalizeEndpoint(path)

	sm.activeRequests.WithLabelValues(normalizedMethod, normalizedEndpoint).Inc()

	return func() {
		sm.activeRequests.WithLabelValues(normalizedMethod, normalizedEndpoint).Dec()
	}
}

// InstrumentedHandler wraps HTTP handlers with metrics
func InstrumentedHandler(sm *SafeMetrics) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()

		// Extract user ID from header (simulating auth)
		userID := r.Header.Get("X-User-ID")

		// Track active requests
		done := sm.TrackActiveRequest(r.Method, r.URL.Path)
		defer done()

		// Wrap response writer to capture status code
		rw := &responseWriter{ResponseWriter: w, statusCode: 200}

		// Route to actual handler
		handleRequest(rw, r)

		duration := time.Since(start)
		sm.RecordRequest(r.Method, r.URL.Path, userID, rw.statusCode, duration)

		if rw.statusCode >= 400 {
			errorType := r.Header.Get("X-Error-Type")
			if errorType == "" {
				errorType = fmt.Sprintf("http_%d", rw.statusCode)
			}
			sm.RecordError(r.Method, r.URL.Path, errorType)
		}
	}
}

type responseWriter struct {
	http.ResponseWriter
	statusCode int
}

func (rw *responseWriter) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

func handleRequest(w http.ResponseWriter, r *http.Request) {
	switch {
	case strings.HasPrefix(r.URL.Path, "/api/v1/users"):
		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, `{"status": "ok", "resource": "users"}`)
	case strings.HasPrefix(r.URL.Path, "/api/v1/orders"):
		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, `{"status": "ok", "resource": "orders"}`)
	case strings.HasPrefix(r.URL.Path, "/api/v1/products"):
		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, `{"status": "ok", "resource": "products"}`)
	case r.URL.Path == "/health":
		w.WriteHeader(http.StatusOK)
		fmt.Fprintf(w, `{"status": "healthy"}`)
	default:
		w.WriteHeader(http.StatusNotFound)
		fmt.Fprintf(w, `{"error": "not found"}`)
	}
}

func main() {
	// Initialize cardinality limiter
	limiter := NewCardinalityLimiter(maxUniqueLabelValues)

	// Initialize label sanitizer with allowlists
	sanitizer := NewLabelSanitizer()
	sanitizer.RegisterAllowedValues("error_type", []string{
		"timeout", "connection_refused", "bad_request", "unauthorized",
		"forbidden", "not_found", "internal_error", "rate_limited",
		"http_400", "http_401", "http_403", "http_404", "http_500", "http_502", "http_503",
	})

	// Create safe metrics
	metrics := NewSafeMetrics(limiter, sanitizer)

	// Start cleanup goroutine
	go func() {
		ticker := time.NewTicker(labelCleanupInterval)
		defer ticker.Stop()
		for range ticker.C {
			limiter.Cleanup(30 * time.Minute)
			log.Println("Completed cardinality limiter cleanup")
		}
	}()

	// Set up HTTP routes
	mux := http.NewServeMux()
	mux.Handle("/metrics", promhttp.Handler())
	mux.HandleFunc("/", InstrumentedHandler(metrics))

	server := &http.Server{
		Addr:         ":8080",
		Handler:      mux,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
	}

	log.Println("Starting server on :8080")
	log.Println("Metrics available at /metrics")
	log.Printf("Cardinality limit: %d unique label combinations per metric", maxUniqueLabelValues)

	if err := server.ListenAndServe(); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}